/// C: `void luaD_call(lua_State *L, StkId func, int nResults)`
pub(crate) fn call(
    state: &mut LuaState,
    func_idx: StackIdx,
    n_results: i32,
) -> Result<(), LuaError> {
    // C: ccall(L, func, nResults, 1)
    ccall_inner(state, func_idx, n_results, 1)
}

